def best_candidates(db, field1='Matn', field2='hadithTxt', topn=15):
    cands = []
    for h in db:
        for field in (field1, field2):
            txt = h.get(field) or ''
            if not txt:
                continue
            sim = combined_sim(orig, txt)
            if sim>0:
                cands.append((sim, field, txt, h.get('title',''), h.get('hadithID')))
    cands.sort(reverse=True, key=lambda x: x[0])
    return cands[:topn]

